import type { Metadata } from "next";
import PutAway from "./PutAway";

export const metadata: Metadata = {
  title: "入庫 / 棚入れ（PUT-AWAY） | ぐんじょう WMS",
  description:
    "入庫 / 棚入れ（PUT-AWAY）の画面。入庫指示番号 / 入荷番号で入庫指示を呼び出し、入荷日 / 倉庫 / 担当者 / 入庫方式（固定ロケーション / フリーロケーション）/ ステータス（未着手 / 棚入れ中 / 完了）を表示。入庫対象明細（商品名 / SKU・JAN / 入荷数量 / 格納済数量 / 推奨ロケーション / 格納先ロケーション / 状態）に対し、ピッキングとは逆順の二段スキャン（① 商品の JAN/SKU をスキャンして明細を特定し推奨棚番を提示 → ② 格納先ロケーションバーコードをスキャンして格納を確定し格納済数量を加算）で棚入れ。推奨ロケーションの空き容量 / 充填率の表示、満杯 / 混載不可 / ゾーン違いの警告と上書き、複数棚への分割格納、入庫確定（全行格納済または保留理由付きまでブロック）/ 一時保存、入庫結果サマリ（ロケーション別格納数）を備えたハンディ端末向けの棚入れツールです。",
};

export default function PutAwayPage() {
  return <PutAway />;
}

// ─────────────────────────────────────────────────────────────────────────────
// 入庫 / 棚入れ — PUT-AWAY domain model & pure logic (WMS)
// 入庫指示呼び出し → 商品スキャン照合 → 推奨ロケーション提示 → 格納先ロケーションスキャン照合
// → 格納数量 / 充填率 → 分割格納 → 入庫確定 → 在庫へ反映
//
// Inbound mirror of picking: scan order is REVERSED (item → location), and the
// system *suggests* where to stow. A line resolves on item scan; the location
// scan confirms placement and increments the stowed qty.
// ─────────────────────────────────────────────────────────────────────────────

/** 入庫方式. */
export type PutAwayMethod = "fixed" | "free";

export const PUT_AWAY_METHOD_LABEL: Record<PutAwayMethod, string> = {
  fixed: "固定ロケーション",
  free: "フリーロケーション",
};

/** 上書き理由 — required to confirm a NON-suggested / mismatched location, or to hold a remainder. */
export type OverrideReason =
  | "location_full"
  | "mixed_not_allowed"
  | "zone_mismatch"
  | "manual_decision";

export const OVERRIDE_REASON_LABEL: Record<OverrideReason, string> = {
  location_full: "推奨棚が満杯",
  mixed_not_allowed: "混載不可",
  zone_mismatch: "ゾーン違い",
  manual_decision: "現場判断",
};

export const OVERRIDE_REASON_OPTIONS: { value: OverrideReason; label: string }[] = (
  Object.keys(OVERRIDE_REASON_LABEL) as OverrideReason[]
).map((value) => ({ value, label: OVERRIDE_REASON_LABEL[value] }));

/** 保留理由 — required to commit while a line still has an un-stowed remainder. */
export type HoldReason = "no_space" | "inspection" | "damaged" | "split_later";

export const HOLD_REASON_LABEL: Record<HoldReason, string> = {
  no_space: "空きロケーション無し",
  inspection: "検品保留",
  damaged: "破損",
  split_later: "後続便で格納",
};

export const HOLD_REASON_OPTIONS: { value: HoldReason; label: string }[] = (
  Object.keys(HOLD_REASON_LABEL) as HoldReason[]
).map((value) => ({ value, label: HOLD_REASON_LABEL[value] }));

// ─── storage locations (the warehouse grid the system suggests into) ─────────

/** A storage bin and its capacity, used for the suggestion + fill display. */
export interface StorageLocation {
  /** 棚番, e.g. "B-07-12". */
  code: string;
  /** バーコード — what the bin label encodes. */
  barcode: string;
  /** ゾーン — for zone-mismatch warnings. */
  zone: string;
  /** 総容量 (units this bin holds). */
  capacity: number;
  /** Units ALREADY stored here before this put-away started. */
  occupied: number;
  /** SKU already resident — drives 混載不可 (mixed-SKU) warnings. "" = empty bin. */
  residentSku: string;
  /** Does this bin allow mixing different SKUs? */
  allowsMixed: boolean;
}

export const LOCATIONS: Record<string, StorageLocation> = {
  "B-07-12": { code: "B-07-12", barcode: "LOC-B-07-12", zone: "B", capacity: 24, occupied: 6, residentSku: "GJ-TOTE-NV-M", allowsMixed: false },
  "B-07-13": { code: "B-07-13", barcode: "LOC-B-07-13", zone: "B", capacity: 24, occupied: 0, residentSku: "", allowsMixed: true },
  "C-02-04": { code: "C-02-04", barcode: "LOC-C-02-04", zone: "C", capacity: 12, occupied: 9, residentSku: "GJ-SNK-250", allowsMixed: false },
  "C-02-05": { code: "C-02-05", barcode: "LOC-C-02-05", zone: "C", capacity: 12, occupied: 2, residentSku: "GJ-SNK-250", allowsMixed: false },
  "A-05-08": { code: "A-05-08", barcode: "LOC-A-05-08", zone: "A", capacity: 40, occupied: 10, residentSku: "", allowsMixed: true },
  "D-01-01": { code: "D-01-01", barcode: "LOC-D-01-01", zone: "D", capacity: 30, occupied: 30, residentSku: "GJ-MUF-CH", allowsMixed: true },
  "D-01-02": { code: "D-01-02", barcode: "LOC-D-01-02", zone: "D", capacity: 30, occupied: 4, residentSku: "GJ-MUF-CH", allowsMixed: true },
};

/** Free space remaining in a bin (never below 0). */
export function locationFree(loc: StorageLocation): number {
  return Math.max(0, loc.capacity - loc.occupied);
}

/** Fill ratio 0..1 BEFORE this put-away. */
export function locationFill(loc: StorageLocation): number {
  return loc.capacity > 0 ? Math.min(1, loc.occupied / loc.capacity) : 1;
}

export type CapacityTone = "ok" | "warning" | "full";

/** Tone for the capacity meter: full at 100%, warning ≥ 80%, else ok. */
export function capacityTone(occupied: number, capacity: number): CapacityTone {
  if (capacity <= 0 || occupied >= capacity) return "full";
  if (occupied / capacity >= 0.8) return "warning";
  return "ok";
}

// ─── one confirmed placement of a line's qty into a specific 棚 ───────────────

export interface Placement {
  id: string;
  location: string; // 棚番 actually used
  qty: number; // units placed here
  /** Was this an override of the suggested/allowed location? */
  override: boolean;
  reason: OverrideReason | "";
}

// ─── stow line (one received item to put away) ───────────────────────────────

export interface StowLine {
  id: string;
  name: string;
  sku: string;
  jan: string; // item barcode scanned to RESOLVE the line (step 1)
  /** 入荷数量 — received qty to stow. */
  received: number;
  /** 単価 (税抜) — for the ¥ summary. */
  unitPrice: number;
  /** 推奨ロケーション — system-suggested 棚番 (primary). */
  suggested: string;
  /** Allowed destinations for this item (suggested first). A scan outside this
   *  set is a mismatch unless overridden. */
  allowedLocations: string[];
  /** Confirmed placements (scan-driven). 格納済 = Σ placement qty. */
  placements: Placement[];
  /** Remainder explicitly held (won't be stowed this session) + reason. */
  held: boolean;
  holdReason: HoldReason | "";
}

// ─── put-away order (入庫指示) ────────────────────────────────────────────────

export interface PutAwayOrder {
  instructionNumber: string; // 入庫指示番号
  receiptNumber: string; // 入荷番号
  receiptDate: string; // 入荷日
  warehouse: string; // 倉庫
  method: PutAwayMethod; // 入庫方式
  operator: string; // 担当者
  lines: StowLine[];
}

// ─── derived per-line ────────────────────────────────────────────────────────

export type LineState = "pending" | "partial" | "complete" | "held";

/** 格納済数量 = Σ placement qty. */
export function lineStowed(l: StowLine): number {
  return l.placements.reduce((s, p) => s + p.qty, 0);
}

/** 残数 = 格納済 − 入荷 (≤ 0 while stowing; 0 when complete). */
export function lineRemaining(l: StowLine): number {
  return lineStowed(l) - l.received;
}

export function lineState(l: StowLine): LineState {
  const stowed = lineStowed(l);
  if (stowed >= l.received) return "complete";
  if (l.held && l.holdReason !== "") return "held";
  if (stowed === 0) return "pending";
  return "partial";
}

export const LINE_STATE_LABEL: Record<LineState, string> = {
  pending: "未",
  partial: "一部",
  complete: "完了",
  held: "保留",
};

/** Settled = fully stowed OR remainder explicitly held with a reason. */
export function lineSettled(l: StowLine): boolean {
  if (lineStowed(l) >= l.received) return true;
  return l.held && l.holdReason !== "";
}

/** A held line still needs a reason — drives the gate. */
export function needsHoldReason(l: StowLine): boolean {
  return l.held && l.holdReason === "";
}

/** Is this line split across more than one 棚? */
export function isSplit(l: StowLine): boolean {
  return l.placements.length > 1;
}

// ─── totals ──────────────────────────────────────────────────────────────────

export const totalReceived = (lines: StowLine[]) => lines.reduce((s, l) => s + l.received, 0);
export const totalStowed = (lines: StowLine[]) => lines.reduce((s, l) => s + lineStowed(l), 0);
export const totalStowedValue = (lines: StowLine[]) =>
  lines.reduce((s, l) => s + lineStowed(l) * l.unitPrice, 0);
export const completedLineCount = (lines: StowLine[]) =>
  lines.filter((l) => lineState(l) === "complete").length;
export const settledLineCount = (lines: StowLine[]) => lines.filter(lineSettled).length;
export const heldLineCount = (lines: StowLine[]) => lines.filter((l) => l.held).length;
export const splitLineCount = (lines: StowLine[]) => lines.filter(isSplit).length;

// ─── projected occupancy: base occupancy + qty stowed THIS session per bin ────

/** Units stowed into `code` across all lines in this session. */
export function sessionStowedAt(lines: StowLine[], code: string): number {
  let n = 0;
  for (const l of lines) for (const p of l.placements) if (p.location === code) n += p.qty;
  return n;
}

/** Projected occupied units in a bin = pre-existing + this session. */
export function projectedOccupied(lines: StowLine[], code: string): number {
  const loc = LOCATIONS[code];
  if (!loc) return 0;
  return loc.occupied + sessionStowedAt(lines, code);
}

/** Free units left in a bin given this session's placements so far. */
export function projectedFree(lines: StowLine[], code: string): number {
  const loc = LOCATIONS[code];
  if (!loc) return 0;
  return Math.max(0, loc.capacity - projectedOccupied(lines, code));
}

// ─── lookup ───────────────────────────────────────────────────────────────────

export function lookupOrder(value: string): PutAwayOrder | null {
  const v = value.trim().toUpperCase();
  return (
    PUT_AWAY_ORDERS.find(
      (o) => o.instructionNumber.toUpperCase() === v || o.receiptNumber.toUpperCase() === v,
    ) ?? null
  );
}

/** Deep-clone lines (incl. placements) so edits don't mutate the seed order. */
export function cloneLines(order: PutAwayOrder): StowLine[] {
  return order.lines.map((l) => ({ ...l, placements: l.placements.map((p) => ({ ...p })) }));
}

// ─── STEP 1: item scan → resolve a stow line (REVERSED vs picking) ────────────

export type ItemScanResult =
  | { kind: "resolved"; lineId: string; name: string; suggested: string; remaining: number }
  | { kind: "complete"; name: string } // already fully stowed
  | { kind: "notfound"; code: string }; // 対象外の商品

/** Resolve a scanned item (JAN/SKU) to a stow line. */
export function matchItemScan(lines: StowLine[], raw: string): ItemScanResult {
  const code = raw.trim();
  const hit = lines.find(
    (l) => l.jan.toUpperCase() === code.toUpperCase() || l.sku.toUpperCase() === code.toUpperCase(),
  );
  if (!hit) return { kind: "notfound", code };
  const remaining = hit.received - lineStowed(hit);
  if (remaining <= 0) return { kind: "complete", name: hit.name };
  return { kind: "resolved", lineId: hit.id, name: hit.name, suggested: hit.suggested, remaining };
}

// ─── STEP 2: location scan → confirm placement against the resolved line ──────

export type LocationMatch = "suggested" | "allowed" | "mismatch" | "unknown";

export interface LocationScanEvaluation {
  match: LocationMatch;
  /** Resolved 棚番 (if the barcode is a known bin). */
  location: string | null;
  /** Why a placement here would be questionable (capacity / mixed / zone). */
  capacityWarning: string | null;
  full: boolean;
  mixedBlocked: boolean;
  zoneMismatch: boolean;
}

/** Resolve a scanned bin barcode to a 棚番 (or null if unknown). */
export function resolveLocationCode(raw: string): string | null {
  const code = raw.trim().toUpperCase();
  const hit = Object.values(LOCATIONS).find(
    (l) => l.barcode.toUpperCase() === code || l.code.toUpperCase() === code,
  );
  return hit ? hit.code : null;
}

/**
 * Evaluate a location scan against the active line: is it the suggested bin, an
 * allowed alt, a mismatch (known bin but not allowed for this item), or unknown?
 * Also surface capacity / mixed-SKU / zone warnings for an informed override.
 */
export function evaluateLocationScan(
  line: StowLine,
  lines: StowLine[],
  raw: string,
): LocationScanEvaluation {
  const code = resolveLocationCode(raw);
  if (!code) {
    return { match: "unknown", location: null, capacityWarning: null, full: false, mixedBlocked: false, zoneMismatch: false };
  }
  const loc = LOCATIONS[code];
  const free = projectedFree(lines, code);
  const full = free <= 0;
  const suggestedZone = LOCATIONS[line.suggested]?.zone;
  const zoneMismatch = suggestedZone != null && loc.zone !== suggestedZone;
  const mixedBlocked = !loc.allowsMixed && loc.residentSku !== "" && loc.residentSku !== line.sku;

  let capacityWarning: string | null = null;
  if (full) capacityWarning = `${code} は満杯です（空き 0）。`;
  else if (mixedBlocked) capacityWarning = `${code} は ${loc.residentSku} 専用で混載不可です。`;
  else if (zoneMismatch) capacityWarning = `${code} はゾーン ${loc.zone}（推奨はゾーン ${suggestedZone}）です。`;

  const isSuggested = code === line.suggested;
  const isAllowed = line.allowedLocations.includes(code);
  const match: LocationMatch = isSuggested ? "suggested" : isAllowed ? "allowed" : "mismatch";

  return { match, location: code, capacityWarning, full, mixedBlocked, zoneMismatch };
}

// ─── completion gate ─────────────────────────────────────────────────────────

export interface PutAwayProblem {
  lineId: string;
  message: string;
}

/** Every line must be fully stowed OR have its remainder held with a reason. */
export function validate(lines: StowLine[]): PutAwayProblem[] {
  const out: PutAwayProblem[] = [];
  for (const l of lines) {
    if (lineSettled(l)) continue;
    if (l.held && l.holdReason === "") {
      out.push({ lineId: l.id, message: `${l.name}：保留理由を選択してください。` });
    } else {
      out.push({
        lineId: l.id,
        message: `${l.name}：${lineStowed(l)}/${l.received} 点。残りを格納するか保留にしてください。`,
      });
    }
  }
  return out;
}

export const canCommit = (lines: StowLine[]) => validate(lines).length === 0;

// ─── seed data ───────────────────────────────────────────────────────────────

export const PUT_AWAY_ORDERS: PutAwayOrder[] = [
  {
    instructionNumber: "PA-2026-0731",
    receiptNumber: "ASN-2026-1188",
    receiptDate: "2026-06-23",
