        sku: "GJ-SNK-250",
        jan: "4901234500028",
        received: 8, // suggested C-02-04 has only 3 free → must split into C-02-05
        unitPrice: 5400,
        suggested: "C-02-04",
        allowedLocations: ["C-02-04", "C-02-05"],
        placements: [],
        held: false,
        holdReason: "",
      },
      {
        id: "S3",
        name: "群青 ウールマフラー チャコール",
        sku: "GJ-MUF-CH",
        jan: "4901234500035",
        received: 20, // suggested D-01-01 is FULL → override to D-01-02 (26 free)
        unitPrice: 3200,
        suggested: "D-01-01",
