  type StowLine,
} from "./data";

const yen = (n: number) => formatCurrency(n, { maximumFractionDigits: 0 });

type Phase = "lookup" | "stowing" | "done";
/** Two-step scan gate — REVERSED vs picking: resolve the item, then confirm its location. */
type ScanStage = "item" | "location";

interface FeedEvent {
  id: number;
  kind: "ok" | "warn" | "error";
  label: string;
  detail: string;
}

const STATE_BADGE_VARIANT: Record<LineState, BadgeProps["variant"]> = {
  pending: "outline",
  partial: "info",
  complete: "success",
  held: "warning",
};

const STATE_ICON: Record<LineState, React.ReactNode> = {
  pending: <IconCircleDot className="h-3.5 w-3.5" aria-hidden="true" />,
  partial: <IconCircleDot className="h-3.5 w-3.5" aria-hidden="true" />,
  complete: <IconCircleCheck className="h-3.5 w-3.5" aria-hidden="true" />,
  held: <IconHandStop className="h-3.5 w-3.5" aria-hidden="true" />,
};

// ─── capacity meter (hand-rolled — no DS primitive for fill% w/ tone) ──────────
const CAP_TONE_BAR: Record<CapacityTone, string> = {
  ok: "bg-success-strong",
  warning: "bg-warning",
  full: "bg-destructive-strong",
};
const CAP_TONE_TEXT: Record<CapacityTone, string> = {
  ok: "text-success-strong",
  warning: "text-warning",
  full: "text-destructive",
};

function CapacityMeter({
  occupied,
  capacity,
  incoming = 0,
  label,
  compact = false,
}: {
  occupied: number;
  capacity: number;
  /** Units about to be added — shown as a striped overlay segment. */
  incoming?: number;
  label: string;
  compact?: boolean;
}) {
  const tone = capacityTone(occupied + incoming, capacity);
  const pct = capacity > 0 ? Math.round(((occupied + incoming) / capacity) * 100) : 100;
  const free = Math.max(0, capacity - occupied - incoming);
  const valueText = `${label} 充填 ${occupied + incoming}/${capacity} 点（${pct}%）、空き ${free} 点`;
  return (
    <div className="flex flex-col gap-1">
      <div className="flex items-center justify-between gap-2 text-xs">
        <span className="text-muted-foreground">{compact ? "充填率" : label}</span>
        <span className={cn("font-medium tabular-nums", CAP_TONE_TEXT[tone])}>
          {pct}%
          <span className="ml-1 font-normal text-muted-foreground">空き {formatNumber(free)}</span>
        </span>
      </div>
      <Progress
        value={occupied + incoming}
        max={capacity || 1}
        label={valueText}
        valueText={valueText}
        className={cn("h-2", compact && "h-1.5")}
        // override the default bg-foreground fill with a threshold tone
        // by styling the inner bar via a CSS var fallback is not exposed, so we
        // layer our own bar absolutely on top.
      />
      {/* tone overlay — Progress' inner bar is always bg-foreground, so paint a
          tone-coloured bar over it at the same width. */}
      <div className="-mt-2.5 h-2 w-full overflow-hidden rounded-full" aria-hidden="true">
        <div
          className={cn("h-full rounded-full transition-all", CAP_TONE_BAR[tone], compact && "h-1.5")}
          style={{ width: `${Math.min(100, pct)}%` }}
        />
      </div>
    </div>
  );
}

export default function PutAway() {
  const [phase, setPhase] = React.useState<Phase>("lookup");
  const [orderInput, setOrderInput] = React.useState("");
  const [lookupError, setLookupError] = React.useState<string | null>(null);

  const [order, setOrder] = React.useState<PutAwayOrder | null>(null);
  const [lines, setLines] = React.useState<StowLine[]>([]);

  // two-step scan gate state (item → location)
  const [scanStage, setScanStage] = React.useState<ScanStage>("item");
  const [activeLineId, setActiveLineId] = React.useState<string | null>(null);
  const [placeQty, setPlaceQty] = React.useState(1);
  // override flow: a mismatched/warned location awaiting a confirmed reason
  const [pendingOverride, setPendingOverride] = React.useState<{
    location: string;
    reason: OverrideReason | "";
    warning: string | null;
  } | null>(null);

  const [feed, setFeed] = React.useState<FeedEvent[]>([]);
  const feedSeq = React.useRef(0);

  const [showErrors, setShowErrors] = React.useState(false);
  const [summaryOpen, setSummaryOpen] = React.useState(false);
  const [splitLineId, setSplitLineId] = React.useState<string | null>(null);
  const [savedAt, setSavedAt] = React.useState<string | null>(null);

  const accepted = phase === "done";
  const activeLine = lines.find((l) => l.id === activeLineId) ?? null;

  const problems = React.useMemo(() => validate(lines), [lines]);
  const problemByLine = React.useMemo(() => {
    const m = new Map<string, string>();
    for (const p of problems) if (!m.has(p.lineId)) m.set(p.lineId, p.message);
    return m;
  }, [problems]);

  // ─── totals / progress ───────────────────────────────────────────────────────
  const received = totalReceived(lines);
  const stowed = totalStowed(lines);
  const completeLines = completedLineCount(lines);
  const settledLines = settledLineCount(lines);
  const heldCount = heldLineCount(lines);
  const splitCount = splitLineCount(lines);
  const stowedValue = totalStowedValue(lines);
  const pct = received ? Math.round((stowed / received) * 100) : 0;

  function pushFeed(e: Omit<FeedEvent, "id">) {
    feedSeq.current += 1;
    const id = feedSeq.current;
    setFeed((prev) => [{ ...e, id }, ...prev].slice(0, 8));
  }

  // ─── order lookup ──────────────────────────────────────────────────────────────
  function resolveOrder(value: string) {
    const found = lookupOrder(value);
    if (!found) {
      setLookupError(
        `「${value}」に一致する入庫指示が見つかりません。入庫指示番号（例 PA-2026-0731）または入荷番号を確認してください。`,
      );
      return;
    }
    setOrder(found);
    setLines(cloneLines(found));
    setLookupError(null);
    setShowErrors(false);
    setSavedAt(null);
    setScanStage("item");
    setActiveLineId(null);
    setPlaceQty(1);
    setPendingOverride(null);
    setFeed([]);
    setPhase("stowing");
  }

  // ─── line mutation ────────────────────────────────────────────────────────────
  const patchLine = React.useCallback((id: string, patch: Partial<StowLine>) => {
    setLines((prev) => prev.map((l) => (l.id === id ? { ...l, ...patch } : l)));
  }, []);

  /** Apply a placement to a line (capped so stowed never exceeds received). */
  const addPlacement = React.useCallback(
    (
      lineId: string,
      location: string,
      qty: number,
      override: boolean,
      reason: OverrideReason | "",
    ): number => {
      let applied = 0;
      setLines((prev) =>
        prev.map((l) => {
          if (l.id !== lineId) return l;
          const remaining = l.received - lineStowed(l);
          applied = Math.max(0, Math.min(qty, remaining));
          if (applied === 0) return l;
          // merge into an existing same-location, same-override placement
          const existing = l.placements.find((p) => p.location === location && p.override === override);
          let placements: Placement[];
          if (existing) {
            placements = l.placements.map((p) =>
              p === existing ? { ...p, qty: p.qty + applied, reason: reason || p.reason } : p,
            );
          } else {
            placements = [
              ...l.placements,
              { id: `${lineId}-${location}-${l.placements.length}`, location, qty: applied, override, reason },
            ];
          }
          return { ...l, placements, held: false, holdReason: "" };
        }),
      );
      return applied;
    },
    [],
  );

  // ─── advance to the next un-stowed line ────────────────────────────────────────
  const goToNextItem = React.useCallback(() => {
    setLines((prev) => {
      const startIdx = prev.findIndex((l) => l.id === activeLineId);
      const len = prev.length;
      for (let step = 1; step <= len; step++) {
        const idx = (((startIdx < 0 ? -1 : startIdx) + step) % len + len) % len;
        if (!lineSettled(prev[idx])) {
          setActiveLineId(prev[idx].id);
          setScanStage("location");
          setPlaceQty(prev[idx].received - lineStowed(prev[idx]));
          setPendingOverride(null);
          return prev;
        }
      }
      setActiveLineId(null);
      setScanStage("item");
      setPendingOverride(null);
      return prev;
    });
  }, [activeLineId]);

  // ─── STEP 1: item scan → resolve a stow line + reveal its suggested location ────
  const handleItemScan = (code: string): ScanResult => {
    const res = matchItemScan(lines, code);
    if (res.kind === "resolved") {
      setActiveLineId(res.lineId);
      setScanStage("location");
      setPlaceQty(res.remaining);
      setPendingOverride(null);
      const free = projectedFree(lines, res.suggested);
      pushFeed({ kind: "ok", label: res.name, detail: `推奨 ${res.suggested}（空き ${free}）` });
      return {
        ok: true,
        message: `${res.name} を特定しました。推奨ロケーション ${res.suggested}（空き ${free} 点）。格納先をスキャンしてください。`,
      };
    }
    if (res.kind === "complete") {
      pushFeed({ kind: "warn", label: res.name, detail: "格納済" });
      return { ok: false, message: `${res.name} は既に全数格納済みです。` };
    }
    pushFeed({ kind: "error", label: res.code, detail: "対象外の商品" });
    return {
      ok: false,
      message: `対象外の商品です（コード ${res.code}）。この入庫指示の対象明細にありません。`,
    };
  };

  // ─── STEP 2: location scan → confirm placement + increment 格納済 ───────────────
  const handleLocationScan = (code: string): ScanResult => {
    if (!activeLine) {
      return { ok: false, message: "先に商品をスキャンして明細を特定してください。" };
    }
    const evalRes = evaluateLocationScan(activeLine, lines, code);
    if (evalRes.match === "unknown" || evalRes.location === null) {
      pushFeed({ kind: "error", label: code, detail: "未知のロケーション" });
      return { ok: false, message: `未知のロケーションです（${code}）。棚番ラベルを確認してください。` };
    }
    const loc = evalRes.location;

    // hard block: a full bin or mixed-not-allowed must be overridden with a reason.
    const blocked = evalRes.full || evalRes.mixedBlocked;
    const questionable = evalRes.match === "mismatch" || evalRes.zoneMismatch || blocked;

    if (questionable) {
      // route into the override gate rather than silently placing
      const presetReason: OverrideReason | "" = evalRes.full
        ? "location_full"
        : evalRes.mixedBlocked
          ? "mixed_not_allowed"
          : evalRes.zoneMismatch
            ? "zone_mismatch"
            : "manual_decision";
      setPendingOverride({ location: loc, reason: presetReason, warning: evalRes.capacityWarning });
      pushFeed({ kind: "warn", label: loc, detail: "ロケーション不一致" });
      return {
        ok: false,
        message:
          (evalRes.capacityWarning ?? `${loc} は推奨/許可ロケーションではありません。`) +
          ` 続行するには上書き理由を選んでください（推奨 ${activeLine.suggested}）。`,
      };
    }

    // clean placement into a suggested / allowed bin with space
    const qty = Math.max(1, placeQty || 1);
    const applied = addPlacement(activeLine.id, loc, qty, evalRes.match !== "suggested", "");
    if (applied === 0) {
      pushFeed({ kind: "warn", label: activeLine.name, detail: "格納済に到達" });
      return { ok: false, message: `${activeLine.name} は入荷数 ${activeLine.received} 点に達しています。` };
    }
    const after = lines
      .map((l) => (l.id === activeLine.id ? l : l))
      .find((l) => l.id === activeLine.id)!;
    const newStowed = lineStowed(after) + applied;
    pushFeed({ kind: "ok", label: activeLine.name, detail: `${loc} へ ${applied} 点` });
    const done = newStowed >= activeLine.received;
    if (done) {
      // line complete — drop back to item scan for the next item
      setScanStage("item");
      setActiveLineId(null);
      setPendingOverride(null);
    } else {
      setPlaceQty(activeLine.received - newStowed);
    }
    return {
      ok: true,
      message: `${activeLine.name} を ${loc} へ ${applied} 点格納（${newStowed} / ${activeLine.received} 点）。${
        done ? "この明細は完了です。次の商品をスキャンしてください。" : "残りは別の棚へ分割格納できます。"
      }`,
    };
  };

  // confirm a pending override placement once a reason is chosen
  function confirmOverride() {
    if (!activeLine || !pendingOverride || pendingOverride.reason === "") return;
    const qty = Math.max(1, placeQty || 1);
    const applied = addPlacement(activeLine.id, pendingOverride.location, qty, true, pendingOverride.reason);
    if (applied > 0) {
      pushFeed({
        kind: "warn",
        label: activeLine.name,
        detail: `上書き ${pendingOverride.location} へ ${applied} 点`,
      });
    }
    const newStowed = lineStowed(activeLine) + applied;
    setPendingOverride(null);
    if (newStowed >= activeLine.received) {
      setScanStage("item");
      setActiveLineId(null);
    } else {
      setPlaceQty(activeLine.received - newStowed);
    }
  }

  // ─── hold-remainder toggle ─────────────────────────────────────────────────────
  function toggleHold(id: string, next: boolean) {
    patchLine(id, next ? { held: true } : { held: false, holdReason: "" });
  }

  // ─── commit ──────────────────────────────────────────────────────────────────
  function attemptCommit() {
    if (!canCommit(lines)) {
      setShowErrors(true);
      return;
    }
    setShowErrors(false);
    setPhase("done");
    setSummaryOpen(false);
  }

  function reset() {
    setPhase("lookup");
    setOrder(null);
    setLines([]);
    setOrderInput("");
    setScanStage("item");
    setActiveLineId(null);
    setPlaceQty(1);
    setPendingOverride(null);
    setFeed([]);
    setShowErrors(false);
    setSavedAt(null);
  }

  // ─── stow-lines grid columns ───────────────────────────────────────────────────
  const columns: EditableColumn<StowLine>[] = [
    {
      id: "name",
      header: "商品 / SKU・JAN",
      minWidth: "13rem",
      cell: (row) => {
        const isActive = activeLine?.id === row.id && !accepted;
        return (
          <div className="flex flex-col">
            <span className="flex items-center gap-1.5 font-medium leading-snug">
              {isActive ? <IconBox className="h-4 w-4 shrink-0 text-primary" aria-hidden="true" /> : null}
              {row.name}
              {isActive ? <span className="sr-only">（スキャン中の明細）</span> : null}
            </span>
            <span className="font-mono text-xs text-muted-foreground tabular-nums">
              {row.sku} · {row.jan}
            </span>
          </div>
        );
      },
    },
    {
      id: "received",
      header: "入荷数量",
      align: "center",
      width: "5.5rem",
      cell: (row) => <span className="tabular-nums">{formatNumber(row.received)}</span>,
    },
    {
      id: "stowed",
      header: "格納済",
      align: "center",
      width: "9rem",
      minWidth: "8.5rem",
      cell: (row, ctx) => {
        const single = row.placements.length <= 1;
        const onlyLoc = row.placements[0]?.location ?? row.suggested;
        if (!single) {
          // split → read-only sum + a hint to open the split editor
          return (
            <div className="flex flex-col items-center gap-0.5">
              <span className="tabular-nums font-medium">{lineStowed(row)}</span>
              <button
                type="button"
                className="inline-flex items-center gap-1 text-xs text-primary underline-offset-2 hover:underline disabled:no-underline disabled:text-muted-foreground"
                onClick={() => setSplitLineId(row.id)}
                disabled={accepted}
              >
                <IconArrowsSplit className="h-3 w-3" aria-hidden="true" />
                {row.placements.length} 棚に分割
              </button>
            </div>
          );
        }
        // single placement → editable stepper (manual adjust), capped at received
        return (
          <NumberInput
            layout="stepper"
            value={lineStowed(row)}
            min={0}
            max={row.received}
            onValueChange={(n) => {
              // manual adjust writes a single placement into the (suggested/used) bin
              const target = row.placements[0]?.location ?? onlyLoc;
              const override = row.placements[0]?.override ?? target !== row.suggested;
              const reason = row.placements[0]?.reason ?? "";
              const placements: Placement[] =
                n <= 0
                  ? []
                  : [{ id: `${row.id}-${target}-0`, location: target, qty: n, override, reason }];
              patchLine(row.id, { placements, held: n > 0 ? false : row.held });
            }}
            aria-label={`${ctx.ariaLabel}（スキャンで加算・手修正可）`}
            disabled={accepted}
          />
        );
      },
    },
    {
      id: "suggested",
      header: "推奨ロケーション",
      align: "center",
      width: "8rem",
      minWidth: "7rem",
      cell: (row) => {
        const loc = LOCATIONS[row.suggested];
        const occ = projectedOccupied(lines, row.suggested);
        const tone = capacityTone(occ, loc.capacity);
        return (
          <div className="flex flex-col items-center gap-0.5">
            <span className="font-mono text-sm tabular-nums">{row.suggested}</span>
            <span
              className={cn(
                "text-[0.7rem] tabular-nums",
                tone === "full" ? "text-destructive" : tone === "warning" ? "text-warning" : "text-muted-foreground",
              )}
            >
              空き {formatNumber(projectedFree(lines, row.suggested))} / {formatNumber(loc.capacity)}
            </span>
          </div>
        );
      },
    },
    {
      id: "actual",
      header: "格納先ロケーション",
      minWidth: "11rem",
      cell: (row) => {
        if (row.placements.length === 0) {
          return <span className="text-xs text-muted-foreground">未格納</span>;
        }
        return (
          <ul className="flex flex-col gap-0.5">
            {row.placements.map((p) => (
              <li key={p.id} className="flex items-center gap-1.5 text-xs">
                <IconMapPin className="h-3.5 w-3.5 shrink-0 text-muted-foreground" aria-hidden="true" />
                <span className="font-mono tabular-nums">{p.location}</span>
                <span className="tabular-nums text-muted-foreground">×{p.qty}</span>
                {p.override ? (
                  <Badge variant="warning" className="h-4 px-1.5 py-0 text-[0.6rem]">
                    上書き
                  </Badge>
                ) : null}
              </li>
            ))}
          </ul>
        );
      },
    },
    {
      id: "remaining",
      header: "残数",
      align: "center",
      width: "7rem",
      minWidth: "6rem",
      cell: (row) => {
        if (row.held) {
          return <span className="text-xs font-medium text-warning">保留</span>;
        }
        const rem = lineRemaining(row); // ≤ 0
        return (
          <Delta
            value={rem}
            format={(n) => (n === 0 ? "0" : formatNumber(Math.abs(n)))}
            hideArrow
            labels={{ negative: "残", zero: "完了" }}
            showLabel
            tones={{ negative: "muted", zero: "success" }}
          />
        );
      },
    },
    {
      id: "state",
      header: "状態",
      align: "center",
      width: "6.5rem",
      cell: (row) => {
        const s = lineState(row);
        return (
          <Badge variant={STATE_BADGE_VARIANT[s]} className="gap-1">
            {STATE_ICON[s]}
            {LINE_STATE_LABEL[s]}
          </Badge>
        );
      },
    },
    {
      id: "hold",
      header: "残量保留",
      minWidth: "13rem",
      cell: (row, ctx) => {
        const reasonMissing = needsHoldReason(row);
        const fullyStowed = lineStowed(row) >= row.received;
        return (
          <div className="flex flex-col gap-2">
            <label className="flex items-center gap-2 text-xs font-medium">
              <input
                type="checkbox"
                className="h-4 w-4 rounded border-input accent-[var(--warning)]"
                checked={row.held}
                onChange={(e) => toggleHold(row.id, e.target.checked)}
                disabled={accepted || fullyStowed}
                aria-label={`${row.name} の残量を保留にする`}
              />
              残量を保留
            </label>
            {row.held ? (
              <Select
                value={row.holdReason}
                onChange={(e) => patchLine(row.id, { holdReason: e.target.value as HoldReason | "" })}
                aria-label={`${ctx.ariaLabel}（保留理由）`}
                aria-invalid={showErrors && reasonMissing ? true : undefined}
                disabled={accepted}
                className="h-8"
              >
                <option value="">保留理由を選択</option>
                {HOLD_REASON_OPTIONS.map((o) => (
                  <option key={o.value} value={o.value}>
                    {o.label}
                  </option>
                ))}
              </Select>
            ) : (
              <span className="text-xs text-muted-foreground">
                {fullyStowed ? "格納完了" : "残りをスキャンで格納"}
              </span>
            )}
          </div>
        );
      },
    },
  ];

  function footerCell(col: EditableColumn<StowLine>) {
    if (col.id === "name") return <span className="font-semibold">合計</span>;
    if (col.id === "received")
      return <span className="font-semibold tabular-nums">{formatNumber(received)}</span>;
    if (col.id === "stowed")
      return <span className="font-semibold tabular-nums">{formatNumber(stowed)}</span>;
    if (col.id === "state")
      return (
        <span className="text-xs font-medium text-muted-foreground tabular-nums">
          完了 {completeLines}/{lines.length} 行
        </span>
      );
    if (col.id === "hold")
      return (
        <span className="text-xs font-medium text-muted-foreground tabular-nums">
          保留 {heldCount} 件 · 分割 {splitCount} 件
        </span>
      );
    return null;
  }

  const splitLine = lines.find((l) => l.id === splitLineId) ?? null;

  // ─── render ─────────────────────────────────────────────────────────────────
  return (
    <main className="mx-auto flex w-full max-w-6xl flex-col gap-6 p-4 sm:p-6">
      <header className="flex flex-col gap-1">
        <h1 className="flex items-center gap-2 text-2xl font-bold tracking-tight">
          <IconPackageImport className="h-6 w-6 shrink-0" aria-hidden="true" />
          入庫 / 棚入れ（PUT-AWAY）
        </h1>
        <p className="text-sm text-muted-foreground">
          入庫指示を呼び出し、商品をスキャンして明細を特定 → 推奨ロケーションを確認し、格納先の棚番をスキャンして格納を確定 —
          容量・混載・分割を処理し、在庫へ反映します。
        </p>
      </header>

      {/* ─── order lookup ─── */}
      {phase === "lookup" ? (
        <Card>
          <CardHeader>
            <CardTitle as="h2" className="flex items-center gap-2 text-lg">
              <IconSearch className="h-5 w-5" aria-hidden="true" />
              入庫指示の呼び出し
            </CardTitle>
            <CardDescription>
              入庫指示番号（または入荷番号）を入力・スキャンして、棚入れ対象を呼び出します。
            </CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4">
            <form
              className="flex flex-col gap-2 sm:flex-row sm:items-end"
              onSubmit={(e) => {
                e.preventDefault();
                if (orderInput.trim()) resolveOrder(orderInput);
              }}
            >
              <div className="flex w-full flex-col gap-1.5">
                <Label htmlFor="order-lookup">入庫指示番号 / 入荷番号</Label>
                <Input
                  id="order-lookup"
                  value={orderInput}
                  onChange={(e) => setOrderInput(e.target.value)}
                  placeholder="PA-2026-0731"
                  autoComplete="off"
                  aria-invalid={lookupError ? true : undefined}
                  aria-describedby={lookupError ? "order-lookup-error" : undefined}
                />
              </div>
              <Button type="submit" disabled={!orderInput.trim()} className="shrink-0">
                <IconSearch className="h-4 w-4" aria-hidden="true" />
                呼び出す
              </Button>
            </form>

            <div aria-live="assertive">
              {lookupError ? (
                <Alert variant="destructive" id="order-lookup-error">
                  <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                  <AlertTitle as="h3">入庫指示が見つかりません</AlertTitle>
                  <AlertDescription>{lookupError}</AlertDescription>
                </Alert>
              ) : null}
            </div>

            <Separator />
            <div className="flex flex-col gap-2">
              <p className="text-xs font-medium text-muted-foreground">本日の棚入れ待ち</p>
              <ul className="flex flex-col gap-2">
                {PUT_AWAY_ORDERS.map((o) => (
                  <li key={o.instructionNumber}>
                    <button
                      type="button"
                      onClick={() => {
                        setOrderInput(o.instructionNumber);
                        resolveOrder(o.instructionNumber);
                      }}
                      className="flex w-full items-center justify-between gap-3 rounded-lg border bg-card p-3 text-left transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                    >
                      <span className="flex flex-col">
                        <span className="font-mono text-sm font-medium">{o.instructionNumber}</span>
                        <span className="text-xs text-muted-foreground">
                          入荷 {o.receiptNumber} · {o.lines.length} 行 · {PUT_AWAY_METHOD_LABEL[o.method]}
                        </span>
                      </span>
                      <Badge variant="outline" className="shrink-0">
                        入荷日 {o.receiptDate}
                      </Badge>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          </CardContent>
        </Card>
      ) : null}

      {/* ─── stowing / done ─── */}
      {order ? (
        <>
          {/* 入庫ヘッダ */}
          <Card>
            <CardHeader className="pb-4">
              <div className="flex flex-wrap items-start justify-between gap-3">
                <div className="flex flex-col gap-1">
                  <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                    <IconPackageImport className="h-5 w-5" aria-hidden="true" />
                    <span className="font-mono">{order.instructionNumber}</span>
                  </CardTitle>
                  <CardDescription>入荷 {order.receiptNumber}</CardDescription>
                </div>
                {accepted ? (
                  <Badge variant="success" className="h-6 gap-1">
                    <IconCircleCheck className="h-3.5 w-3.5" aria-hidden="true" />
                    完了
                  </Badge>
                ) : stowed > 0 ? (
                  <Badge variant="info" className="h-6">
                    棚入れ中
                  </Badge>
                ) : (
                  <Badge variant="outline" className="h-6">
                    未着手
                  </Badge>
                )}
              </div>
            </CardHeader>
            <CardContent>
              <dl className="grid grid-cols-2 gap-x-4 gap-y-3 text-sm sm:grid-cols-3 lg:grid-cols-6">
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconCalendarEvent className="h-3.5 w-3.5" aria-hidden="true" />
                    入荷日
                  </dt>
                  <dd className="tabular-nums">{order.receiptDate}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconBuildingWarehouse className="h-3.5 w-3.5" aria-hidden="true" />
                    倉庫
                  </dt>
                  <dd>{order.warehouse}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">入荷番号</dt>
                  <dd className="font-mono tabular-nums">{order.receiptNumber}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">入庫方式</dt>
                  <dd>{PUT_AWAY_METHOD_LABEL[order.method]}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconUser className="h-3.5 w-3.5" aria-hidden="true" />
                    担当者
                  </dt>
                  <dd>{order.operator}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">明細行数</dt>
                  <dd className="tabular-nums">{order.lines.length} 行</dd>
                </div>
              </dl>
            </CardContent>
          </Card>

          {/* 進捗 */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <IconClipboardList className="h-5 w-5" aria-hidden="true" />
                棚入れ進捗
              </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
                <Statistic label="完了行" value={`${completeLines} / ${lines.length} 行`} hint={`保留 ${heldCount} 件`} />
                <Statistic
                  label="格納点数"
                  value={`${formatNumber(stowed)} / ${formatNumber(received)} 点`}
                  hint={`達成 ${pct}%`}
                />
                <Statistic
                  label="未処理行"
                  value={`${formatNumber(lines.length - settledLines)} 行`}
                  trend={lines.length - settledLines > 0 ? "down" : "flat"}
                  tone={lines.length - settledLines > 0 ? "negative" : "neutral"}
                  change={lines.length - settledLines > 0 ? "残あり" : "なし"}
                />
                <Statistic label="入庫金額" value={yen(stowedValue)} hint={`分割 ${splitCount} 件`} />
              </div>
              <div className="flex flex-col gap-1.5">
                <div className="flex items-center justify-between text-xs font-medium text-muted-foreground">
                  <span>全体の進捗</span>
                  <span className="tabular-nums">
                    {formatNumber(stowed)} / {formatNumber(received)} 点（{pct}%）
                  </span>
                </div>
                <Progress
                  value={stowed}
                  max={received || 1}
                  label="棚入れ全体の進捗"
                  valueText={`格納 ${stowed} / ${received} 点（${pct}%）`}
                />
              </div>
            </CardContent>
          </Card>

          {/* 2段スキャン — the centerpiece (item → location, reversed) */}
          {!accepted ? (
            <Card>
              <CardHeader className="pb-3">
                <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                  <IconScan className="h-5 w-5" aria-hidden="true" />
                  スキャン照合（商品 → 格納先ロケーション）
                </CardTitle>
                <CardDescription>
                  ① 商品の JAN/SKU をスキャンして明細を特定し、推奨ロケーションを確認 → ② 格納先の棚番バーコードをスキャンすると、その明細の格納済数量が加算されます。
                </CardDescription>
              </CardHeader>
              <CardContent className="flex flex-col gap-4">
                {/* active-item pointer + suggested location */}
                {activeLine ? (
                  <div className="flex flex-col gap-2 rounded-lg border bg-muted/30 p-3">
                    <div className="flex flex-wrap items-center justify-between gap-2">
                      <div className="flex items-center gap-2">
                        <IconBox className="h-4 w-4 text-primary" aria-hidden="true" />
                        <span className="text-sm font-medium">{activeLine.name}</span>
                      </div>
                      <span className="text-sm text-muted-foreground tabular-nums">
                        格納 {lineStowed(activeLine)} / {activeLine.received} 点
                      </span>
                    </div>
                    <div className="flex flex-wrap items-center gap-2 text-sm">
                      <span className="text-muted-foreground">推奨ロケーション</span>
                      <span className="font-mono text-base font-semibold tabular-nums">{activeLine.suggested}</span>
                    </div>
                    <CapacityMeter
                      occupied={projectedOccupied(lines, activeLine.suggested)}
                      capacity={LOCATIONS[activeLine.suggested].capacity}
                      label={`推奨棚 ${activeLine.suggested}`}
                    />
                  </div>
                ) : null}

                {/* stage stepper (reversed: ① 商品 → ② ロケーション) */}
                <ol className="flex items-center gap-2 text-sm" aria-label="スキャン手順">
                  <li
                    className={
                      scanStage === "item"
                        ? "flex items-center gap-1.5 font-semibold text-primary"
                        : "flex items-center gap-1.5 text-success-strong"
                    }
                  >
                    {activeLine ? (
                      <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                    ) : (
                      <IconCircleDot className="h-4 w-4" aria-hidden="true" />
                    )}
                    ① 商品
                  </li>
                  <IconArrowRight className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
                  <li
                    className={
                      scanStage === "location"
                        ? "flex items-center gap-1.5 font-semibold text-primary"
                        : "flex items-center gap-1.5 text-muted-foreground"
                    }
                  >
                    <IconCircleDot className="h-4 w-4" aria-hidden="true" />② 格納先ロケーション
                  </li>
                </ol>

                {/* STEP 1 — item scan */}
                {scanStage === "item" ? (
                  <ScanInput
                    key="item-scan"
                    label="① 商品をスキャン"
                    description="商品の JAN / SKU をスキャン（または入力して Enter）すると明細を特定し、推奨ロケーションを表示します。"
                    placeholder="商品をスキャン…（例 4901234500011）"
                    icon={<IconBox className="h-4 w-4" aria-hidden="true" />}
                    inputMode="numeric"
                    onScan={handleItemScan}
                    autoFocus
                  />
                ) : (
                  /* STEP 2 — location scan (only after an item is resolved) */
                  <div className="flex flex-col gap-3">
                    <Alert variant="info">
                      <IconBox className="h-4 w-4" aria-hidden="true" />
                      <AlertTitle as="h3">{activeLine?.name} を格納します</AlertTitle>
                      <AlertDescription>
                        推奨ロケーション <span className="font-mono font-medium">{activeLine?.suggested}</span> の棚番バーコードをスキャンしてください。別の棚へ入れる場合はその棚番をスキャンすると不一致警告が出ます。
                      </AlertDescription>
                    </Alert>

                    {/* placement qty (defaults to the remaining qty; lets the staffer place fewer for a split) */}
                    <div className="flex flex-wrap items-end gap-3">
                      <div className="flex flex-col gap-1.5">
                        <Label htmlFor="place-qty">この棚へ格納する数量</Label>
                        <NumberInput
                          id="place-qty"
                          layout="stepper"
                          value={placeQty}
                          min={1}
                          max={activeLine ? activeLine.received - lineStowed(activeLine) : 1}
                          onValueChange={setPlaceQty}
                          aria-label="この棚へ格納する数量"
                        />
                      </div>
                      <p className="pb-2 text-xs text-muted-foreground">
                        残り {activeLine ? activeLine.received - lineStowed(activeLine) : 0} 点。満杯の棚は分割して次の棚へ。
                      </p>
                    </div>

                    <ScanInput
                      key={`loc-${activeLineId}`}
                      label="② 格納先ロケーションをスキャン"
                      description="格納先の棚番ラベルをスキャン（または入力して Enter）すると、上で指定した数量が格納されます。"
                      placeholder="棚番ラベルをスキャン…（例 LOC-B-07-12）"
                      icon={<IconMapPin className="h-4 w-4" aria-hidden="true" />}
                      inputMode="text"
                      onScan={handleLocationScan}
                      autoFocus
                    />

                    {/* override gate — a mismatched / full / mixed / zone location awaiting a reason */}
                    <RevealSection open={pendingOverride !== null} label="ロケーション上書き">
                      {pendingOverride ? (
                        <Alert variant="warning">
                          <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                          <AlertTitle as="h3">ロケーション不一致 — 上書きの確認</AlertTitle>
                          <AlertDescription>
                            <div className="flex flex-col gap-2">
                              <span>
                                {pendingOverride.warning ??
                                  `${pendingOverride.location} は推奨/許可ロケーションではありません。`}{" "}
                                推奨は <span className="font-mono">{activeLine?.suggested}</span> です。
                              </span>
                              <div className="flex flex-col gap-1.5">
                                <Label htmlFor="override-reason">上書き理由</Label>
                                <Select
                                  id="override-reason"
                                  value={pendingOverride.reason}
                                  onChange={(e) =>
                                    setPendingOverride((p) =>
                                      p ? { ...p, reason: e.target.value as OverrideReason | "" } : p,
                                    )
                                  }
                                  className="h-9 max-w-xs"
                                >
                                  <option value="">上書き理由を選択</option>
                                  {OVERRIDE_REASON_OPTIONS.map((o) => (
                                    <option key={o.value} value={o.value}>
                                      {o.label}
                                    </option>
                                  ))}
                                </Select>
                              </div>
                              <div className="flex flex-wrap gap-2">
                                <Button
                                  variant="warning"
                                  size="sm"
                                  onClick={confirmOverride}
                                  disabled={pendingOverride.reason === ""}
                                >
                                  <IconMapPin className="h-4 w-4" aria-hidden="true" />
                                  {pendingOverride.location} へ {Math.max(1, placeQty || 1)} 点 上書き格納
                                </Button>
                                <Button variant="ghost" size="sm" onClick={() => setPendingOverride(null)}>
                                  <IconX className="h-4 w-4" aria-hidden="true" />
                                  取消
                                </Button>
                              </div>
                            </div>
                          </AlertDescription>
                        </Alert>
                      ) : null}
                    </RevealSection>

                    <Button
                      variant="outline"
                      size="sm"
                      className="self-start"
                      onClick={() => {
                        setScanStage("item");
                        setActiveLineId(null);
                        setPendingOverride(null);
                      }}
                    >
                      <IconBarcode className="h-4 w-4" aria-hidden="true" />
                      商品スキャンに戻る
                    </Button>
                  </div>
                )}

                {/* recent scan feed */}
                {feed.length ? (
                  <div className="flex flex-col gap-1.5">
                    <p className="text-xs font-medium text-muted-foreground">最近のスキャン</p>
                    <ul className="flex flex-col gap-1">
                      {feed.map((f) => (
                        <li
                          key={f.id}
                          className="flex items-center justify-between gap-2 rounded-md border bg-muted/30 px-2.5 py-1.5 text-xs"
                        >
                          <span className="flex items-center gap-2 truncate">
                            <Badge variant={f.kind === "ok" ? "success" : f.kind === "warn" ? "warning" : "destructive"}>
                              {f.kind === "ok" ? "OK" : f.kind === "warn" ? "注意" : "対象外"}
                            </Badge>
                            <span className="truncate font-medium">{f.label}</span>
                          </span>
                          <span className="shrink-0 font-mono tabular-nums text-muted-foreground">{f.detail}</span>
                        </li>
                      ))}
                    </ul>
                  </div>
                ) : null}
              </CardContent>
            </Card>
          ) : null}

          {/* 入庫対象明細 */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <IconClipboardCheck className="h-5 w-5" aria-hidden="true" />
                入庫対象明細
              </CardTitle>
              <CardDescription>
                商品スキャンで明細を特定し、格納先ロケーションのスキャンで格納済が加算され、残数・状態が自動更新されます。
                残量が格納できない行は「残量を保留」を選び、保留理由を記録します。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <EditableDataTable
                columns={columns}
                rows={lines}
                getRowId={(l) => l.id}
                rowLabel={(i) => lines[i]?.name ?? `行 ${i + 1}`}
                getRowError={showErrors ? (row) => problemByLine.get(row.id) : undefined}
                renderFooterCell={footerCell}
                caption="入庫対象明細 — 商品→ロケーションのスキャンで格納済が加算され、残数・状態が自動更新されます。"
              />
            </CardContent>
          </Card>

          {/* hold gate */}
          <RevealSection open={!accepted && heldCount > 0} label="残量保留処理">
            <Alert variant="warning">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">残量保留の理由が必要です（{heldCount} 件）</AlertTitle>
              <AlertDescription>
                保留にした行には「保留理由」（空きロケーション無し / 検品保留 / 破損 / 後続便で格納）が必要です。
                理由を選択するまで入庫確定はできません。
              </AlertDescription>
            </Alert>
          </RevealSection>

          {/* validation summary on commit attempt */}
          <RevealSection open={showErrors && problems.length > 0} label="入庫確定エラー">
            <Alert variant="destructive">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">入庫を確定できません（{problems.length} 件）</AlertTitle>
              <AlertDescription>
                <ul className="ml-4 list-disc">
                  {problems.map((p) => (
                    <li key={`${p.lineId}-${p.message}`}>{p.message}</li>
                  ))}
                </ul>
              </AlertDescription>
            </Alert>
          </RevealSection>

          {/* completion confirmation */}
          {accepted ? (
            <Alert variant="success">
              <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">入庫確定 — 在庫へ反映しました</AlertTitle>
              <AlertDescription>
                {order.instructionNumber}（入荷 {order.receiptNumber}）の棚入れを確定しました。格納 {formatNumber(stowed)} 点 · 保留{" "}
                {formatNumber(heldCount)} 件 · 分割 {formatNumber(splitCount)} 件 · 金額 {yen(stowedValue)}。ロケーション別の在庫が更新されました。
              </AlertDescription>
            </Alert>
          ) : null}

          {/* actions */}
          <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
            <div className="text-xs text-muted-foreground" aria-live="polite">
              {accepted
                ? "この入庫は確定済みです（読み取り専用）。"
                : savedAt
                  ? `一時保存しました（${savedAt}）。`
                  : `格納 ${formatNumber(stowed)} / ${formatNumber(received)} 点 · 完了 ${completeLines}/${lines.length} 行 · 保留 ${heldCount} 件 · 分割 ${splitCount} 件`}
            </div>
            <div className="flex flex-wrap items-center gap-2">
              {accepted ? (
                <>
                  <Button variant="outline" onClick={() => setSummaryOpen(true)}>
                    <IconClipboardList className="h-4 w-4" aria-hidden="true" />
                    入庫結果
                  </Button>
                  <Button variant="secondary" onClick={reset}>
                    新しい入庫指示を棚入れ
                  </Button>
                </>
              ) : (
                <>
                  <Button
                    variant="ghost"
                    onClick={() => {
                      setSavedAt(
                        new Date().toLocaleTimeString("ja-JP", { hour: "2-digit", minute: "2-digit" }),
                      );
                    }}
                  >
                    <IconDeviceFloppy className="h-4 w-4" aria-hidden="true" />
                    一時保存
                  </Button>
                  <Button variant="outline" onClick={goToNextItem} disabled={settledLines >= lines.length}>
                    <IconStack2 className="h-4 w-4" aria-hidden="true" />
                    次の商品へ
                  </Button>
                  <Button variant="outline" onClick={() => setSummaryOpen(true)}>
                    <IconClipboardList className="h-4 w-4" aria-hidden="true" />
                    結果サマリ
                  </Button>
                  <Button variant="success" onClick={attemptCommit} disabled={stowed === 0 && heldCount === 0}>
                    <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                    入庫確定
                  </Button>
                </>
              )}
            </div>
          </div>
        </>
      ) : null}

      {/* 分割格納エディタ (split editor) */}
      <Dialog open={splitLine !== null} onOpenChange={(o) => !o && setSplitLineId(null)}>
        <DialogContent className="max-h-[85vh] overflow-y-auto sm:max-w-md">
          <DialogHeader>
            <DialogTitle>分割格納 — {splitLine?.name}</DialogTitle>
            <DialogDescription>
              この明細は複数の棚に分割して格納されています。各棚の格納数量の合計が格納済数量になります。
            </DialogDescription>
          </DialogHeader>
          {splitLine ? (
            <div className="flex flex-col gap-3 text-sm">
              <ul className="flex flex-col divide-y">
                {splitLine.placements.map((p) => (
                  <li key={p.id} className="flex items-center justify-between gap-3 py-2">
                    <span className="flex items-center gap-2">
                      <IconMapPin className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
                      <span className="font-mono tabular-nums">{p.location}</span>
                      {p.override ? (
                        <Badge variant="warning" className="h-5">
                          上書き{p.reason ? `・${OVERRIDE_REASON_LABEL[p.reason]}` : ""}
                        </Badge>
                      ) : null}
                    </span>
                    <span className="tabular-nums font-medium">{p.qty} 点</span>
                  </li>
                ))}
              </ul>
              <Separator />
              <dl className="flex flex-col gap-1.5">
                <div className="flex justify-between">
                  <dt className="text-muted-foreground">入荷数量</dt>
                  <dd className="tabular-nums">{formatNumber(splitLine.received)} 点</dd>
                </div>
                <div className="flex justify-between font-semibold">
                  <dt>格納済合計</dt>
                  <dd className="tabular-nums">{formatNumber(lineStowed(splitLine))} 点</dd>
                </div>
              </dl>
            </div>
          ) : null}
          <DialogFooter>
            <Button variant="outline" onClick={() => setSplitLineId(null)}>
              <IconX className="h-4 w-4" aria-hidden="true" />
              閉じる
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* 入庫結果サマリ — stowed counts by location */}
      <Dialog open={summaryOpen} onOpenChange={setSummaryOpen}>
        <DialogContent className="max-h-[85vh] overflow-y-auto sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>入庫結果サマリ — {order?.instructionNumber}</DialogTitle>
            <DialogDescription>
              入荷 {order?.receiptNumber} · 入荷日 {order?.receiptDate} · {order?.warehouse}
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-3 text-sm">
            <p className="text-xs font-medium text-muted-foreground">明細別</p>
            <ul className="flex flex-col divide-y">
              {lines.map((l) => {
                const s = lineState(l);
                return (
                  <li key={l.id} className="flex items-center justify-between gap-3 py-2">
                    <span className="flex flex-col">
                      <span className="font-medium">{l.name}</span>
                      <span className="font-mono text-xs text-muted-foreground tabular-nums">
                        格納 {lineStowed(l)} / 入荷 {l.received}
                        {l.placements.length ? ` · ${l.placements.map((p) => `${p.location}×${p.qty}`).join(" / ")}` : ""}
                      </span>
                    </span>
                    <span className="flex shrink-0 items-center gap-2">
                      {isSplit(l) ? (
                        <Badge variant="outline" className="gap-1">
                          <IconArrowsSplit className="h-3 w-3" aria-hidden="true" />分割
                        </Badge>
                      ) : null}
                      <Badge variant={STATE_BADGE_VARIANT[s]} className="gap-1">
                        {STATE_ICON[s]}
                        {LINE_STATE_LABEL[s]}
                      </Badge>
                    </span>
                  </li>
                );
              })}
            </ul>
            <Separator />
            {/* by-location rollup */}
            <p className="text-xs font-medium text-muted-foreground">ロケーション別 格納数</p>
            <ul className="flex flex-col gap-1">
              {Object.entries(
                lines
                  .flatMap((l) => l.placements)
                  .reduce<Record<string, number>>((acc, p) => {
                    acc[p.location] = (acc[p.location] ?? 0) + p.qty;
                    return acc;
                  }, {}),
              ).map(([loc, qty]) => (
                <li key={loc} className="flex items-center justify-between gap-3">
                  <span className="flex items-center gap-1.5">
                    <IconMapPin className="h-3.5 w-3.5 text-muted-foreground" aria-hidden="true" />
                    <span className="font-mono tabular-nums">{loc}</span>
                  </span>
                  <span className="tabular-nums">{formatNumber(qty)} 点</span>
                </li>
              ))}
            </ul>
            <Separator />
            <dl className="flex flex-col gap-1.5">
              <div className="flex justify-between">
                <dt className="text-muted-foreground">入荷合計</dt>
                <dd className="tabular-nums">{formatNumber(received)} 点</dd>
              </div>
              <div className="flex justify-between">
                <dt className="text-muted-foreground">格納合計</dt>
                <dd className="tabular-nums">{formatNumber(stowed)} 点</dd>
              </div>
              <div className="flex justify-between">
                <dt className="text-muted-foreground">保留件数</dt>
                <dd className="tabular-nums">{formatNumber(heldCount)} 件</dd>
              </div>
              <div className="flex justify-between font-semibold">
                <dt>入庫金額</dt>
                <dd className="tabular-nums">{yen(stowedValue)}</dd>
              </div>
            </dl>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setSummaryOpen(false)}>
              <IconX className="h-4 w-4" aria-hidden="true" />
              閉じる
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}
